/* ── App ── */
export default function App() {
  const [page, setPage] = useState("home");
  const nav = p=>{ setPage(p); window.scrollTo({top:0,behavior:"smooth"}); };
  return (
    <div style={{ fontFamily:FB, background:C.bg, color:C.text, minHeight:"100vh", overflowX:"hidden" }}>
      <Header page={page} nav={nav}/>
      {page==="home"      && <HomePage nav={nav}/>}
      {page==="diensten"  && <DienstenPage nav={nav}/>}
      {page==="over-ons"  && <OverOnsPage nav={nav}/>}
      {page==="projecten" && <ProjectenPage nav={nav}/>}
      {page==="contact"   && <ContactPage/>}
      {page==="offerte"   && <OffertePage/>}
      <Footer nav={nav}/>
    </div>
  );
}
